SELECT a.* FROM app_beauty_price_detail a
  WHERE  user_b_id = #{userB}
  AND beauty_type = #{beautyType}
  AND preferential_price = (SELECT MIN(b.preferential_price)FROM app_beauty_price_detail b WHERE  b.user_b_id = #{userB} AND b.beauty_type = #{beautyType})

        SELECT a.*,b.beauty_name beautyName FROM app_beauty_price_detail as a
